const functions = require('@google-cloud/functions-framework');
const { BigQuery } = require('@google-cloud/bigquery');
const { SecretManagerServiceClient } = require('@google-cloud/secret-manager');

// Input validation constants
const ALLOWED_DATASETS = new Set([
  'analytics',
  'sales',
  'inventory',
  'customer_metrics',
  'financial_reports'
]);

const ALLOWED_AGGREGATIONS = new Set([
  'SUM',
  'AVG',
  'COUNT',
  'MIN',
  'MAX',
  'COUNT_DISTINCT'
]);

const MAX_DATE_RANGE_DAYS = 365;
const DATASET_ID_REGEX = /^[a-z][a-z0-9_]{0,63}$/;
const TABLE_ID_REGEX = /^[a-zA-Z][a-zA-Z0-9_]{0,127}$/;
const COLUMN_NAME_REGEX = /^[a-zA-Z_][a-zA-Z0-9_]{0,127}$/;

let secretManagerClient;

function getSecretManagerClient() {
  if (!secretManagerClient) {
    secretManagerClient = new SecretManagerServiceClient();
  }
  return secretManagerClient;
}

async function getSecret(secretName) {
  const client = getSecretManagerClient();
  const projectId = process.env.GCP_PROJECT || process.env.GCLOUD_PROJECT;
  const name = `projects/${projectId}/secrets/${secretName}/versions/latest`;

  const [version] = await client.accessSecretVersion({ name });
  return version.payload.data.toString('utf8');
}

function sanitizeForLogging(value) {
  if (typeof value === 'string') {
    return value.replace(/[^\w\s\-_.]/g, '*').substring(0, 100);
  }
  return String(value).substring(0, 100);
}

function validateDatasetName(dataset) {
  if (!dataset || typeof dataset !== 'string') {
    throw new InputValidationError('Dataset name is required and must be a string');
  }
  const trimmed = dataset.trim().toLowerCase();
  if (!ALLOWED_DATASETS.has(trimmed)) {
    throw new InputValidationError(
      `Dataset '${sanitizeForLogging(trimmed)}' is not in the allowed list`
    );
  }
  if (!DATASET_ID_REGEX.test(trimmed)) {
    throw new InputValidationError('Dataset name contains invalid characters');
  }
  return trimmed;
}

function validateTableName(table) {
  if (!table || typeof table !== 'string') {
    throw new InputValidationError('Table name is required and must be a string');
  }
  const trimmed = table.trim();
  if (!TABLE_ID_REGEX.test(trimmed)) {
    throw new InputValidationError('Table name contains invalid characters');
  }
  if (trimmed.length > 128) {
    throw new InputValidationError('Table name exceeds maximum length');
  }
  return trimmed;
}

function validateColumnNames(columns) {
  if (!Array.isArray(columns) || columns.length === 0) {
    throw new InputValidationError('Columns must be a non-empty array');
  }
  if (columns.length > 50) {
    throw new InputValidationError('Too many columns specified (max 50)');
  }
  return columns.map((col) => {
    if (typeof col !== 'string') {
      throw new InputValidationError('Each column must be a string');
    }
    const trimmed = col.trim();
    if (!COLUMN_NAME_REGEX.test(trimmed)) {
      throw new InputValidationError(
        `Column name '${sanitizeForLogging(trimmed)}' contains invalid characters`
      );
    }
    return trimmed;
  });
}

function validateAggregationType(aggregation) {
  if (!aggregation || typeof aggregation !== 'string') {
    throw new InputValidationError('Aggregation type is required');
  }
  const upper = aggregation.trim().toUpperCase();
  if (!ALLOWED_AGGREGATIONS.has(upper)) {
    throw new InputValidationError(
      `Aggregation '${sanitizeForLogging(upper)}' is not supported. Allowed: ${[...ALLOWED_AGGREGATIONS].join(', ')}`
    );
  }
  return upper;
}

function validateDateRange(startDate, endDate) {
  if (!startDate || !endDate) {
    throw new InputValidationError('Both startDate and endDate are required');
  }

  const start = new Date(startDate);
  const end = new Date(endDate);

  if (isNaN(start.getTime()) || isNaN(end.getTime())) {
    throw new InputValidationError('Invalid date format. Use ISO 8601 format');
  }

  if (start > end) {
    throw new InputValidationError('startDate must be before endDate');
  }

  const diffDays = (end - start) / (1000 * 60 * 60 * 24);
  if (diffDays > MAX_DATE_RANGE_DAYS) {
    throw new InputValidationError(
      `Date range exceeds maximum of ${MAX_DATE_RANGE_DAYS} days`
    );
  }

  return {
    startDate: start.toISOString().split('T')[0],
    endDate: end.toISOString().split('T')[0]
  };
}

function validateGroupByColumns(groupBy, validColumns) {
  if (!groupBy) return [];
  if (!Array.isArray(groupBy)) {
    throw new InputValidationError('groupBy must be an array');
  }
  if (groupBy.length > 10) {
    throw new InputValidationError('Too many groupBy columns (max 10)');
  }
  return groupBy.map((col) => {
    if (typeof col !== 'string') {
      throw new InputValidationError('Each groupBy column must be a string');
    }
    const trimmed = col.trim();
    if (!COLUMN_NAME_REGEX.test(trimmed)) {
      throw new InputValidationError(
        `GroupBy column '${sanitizeForLogging(trimmed)}' contains invalid characters`
      );
    }
    return trimmed;
  });
}

function validateLimit(limit) {
  if (limit === undefined || limit === null) {
    return 10000;
  }
  const parsed = parseInt(limit, 10);
  if (isNaN(parsed) || parsed < 1 || parsed > 1000000) {
    throw new InputValidationError('Limit must be between 1 and 1,000,000');
  }
  return parsed;
}

class InputValidationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'InputValidationError';
    this.statusCode = 400;
  }
}

function buildParameterizedQuery(params) {
  const {
    dataset,
    table,
    aggregation,
    aggregateColumn,
    groupByColumns,
    dateColumn,
    dates,
    limit
  } = params;

  const qualifiedTable = `\`${dataset}.${table}\``;

  let aggregateExpression;
  if (aggregation === 'COUNT_DISTINCT') {
    aggregateExpression = `COUNT(DISTINCT \`${aggregateColumn}\`)`;
  } else {
    aggregateExpression = `${aggregation}(\`${aggregateColumn}\`)`;
  }

  const selectParts = [];
  if (groupByColumns.length > 0) {
    groupByColumns.forEach((col) => {
      selectParts.push(`\`${col}\``);
    });
  }
  selectParts.push(`${aggregateExpression} AS aggregated_value`);
  selectParts.push('COUNT(*) AS row_count');

  let query = `SELECT ${selectParts.join(', ')} FROM ${qualifiedTable}`;

  const queryParams = {};

  if (dateColumn && dates) {
    query += ` WHERE \`${dateColumn}\` BETWEEN @startDate AND @endDate`;
    queryParams.startDate = dates.startDate;
    queryParams.endDate = dates.endDate;
  }

  if (groupByColumns.length > 0) {
    const groupByClause = groupByColumns.map((col) => `\`${col}\``).join(', ');
    query += ` GROUP BY ${groupByClause}`;
    query += ` ORDER BY aggregated_value DESC`;
  }

  query += ` LIMIT @resultLimit`;
  queryParams.resultLimit = limit;

  return { query, queryParams };
}

async function processInBatches(bigquery, query, queryParams, batchSize = 100000) {
  const results = [];
  let offset = 0;
  let hasMore = true;

  while (hasMore) {
    const batchQuery = `${query} OFFSET @batchOffset`;
    const batchParams = {
      ...queryParams,
      batchOffset: offset
    };

    const options = {
      query: batchQuery,
      params: batchParams,
      types: {
        startDate: 'STRING',
        endDate: 'STRING',
        resultLimit: 'INT64',
        batchOffset: 'INT64'
      },
      useLegacySql: false,
      maximumBytesBilled: '10737418240' // 10GB safety limit
    };

    const [rows] = await bigquery.query(options);

    if (rows.length === 0) {
      hasMore = false;
    } else {
      results.push(...rows);
      offset += batchSize;

      if (rows.length < batchSize) {
        hasMore = false;
      }
    }

    if (results.length >= queryParams.resultLimit) {
      hasMore = false;
    }
  }

  return results.slice(0, queryParams.resultLimit);
}

async function authenticateRequest(req) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    throw Object.assign(new Error('Missing or invalid authorization header'), {
      statusCode: 401
    });
  }

  const token = authHeader.substring(7);

  const expectedTokenHash = await getSecret('bigdata-processor-api-token-hash');

  const crypto = require('crypto');
  const providedHash = crypto.createHash('sha256').update(token).digest('hex');

  if (!crypto.timingSafeEqual(
    Buffer.from(providedHash, 'hex'),
    Buffer.from(expectedTokenHash, 'hex')
  )) {
    throw Object.assign(new Error('Invalid authentication token'), {
      statusCode: 403
    });
  }

  return true;
}

